var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈은…….","JPN":"貴様は……","ENG":"You are...","TWN":"你這傢伙……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"과연, 애송이 몸에 남아있던 마창의 잔여물이 환영으로 구현된 건가?","JPN":"なるほど、小娘の体に残っていた魔槍の残滓が幻影として具現化されたのか？","ENG":"I see, so the remnants of the evil spear in that kid's body manifested as an illusion?","TWN":"果然，留在丫頭體內的魔槍殘留物化作幻影了嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"죽어서까지 계집 하나 지키려 들다니. 이것 참 눈물나는 가족애로군.","JPN":"死んでまで小娘を守ろうとするとは。涙ぐましい家族愛だ。","ENG":"Even in death, still trying to protect some girl? Truly heartwarming familial devotion.","TWN":"死了還要保護一個小丫頭。真是令人感動的親情啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈의 허튼 수작질이 그림자 때 묻혀버린 이성이라도 되찾아줄 거라 믿는 건가?","JPN":"貴様の小細工が、シャドウになって埋もれてしまった理性を取り戻してくれるとでも信じているのか？","ENG":"Do you really believe your pitiful trick will somehow restore her Shadow-tainted sanity?","TWN":"你以為你的胡鬧能幫我找回被暗影污染的理智嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……닮았군.","JPN":"……似ているな。","ENG":"...You're just like him.","TWN":"真像啊。"},"stage":{"bg":"MS_903","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"허나 네놈에게는 누군가의 의무를 짊어질 책임이 없다.","JPN":"だが、貴様には誰かの義務を背負う責任がない。","ENG":"But unlike him, you carry no sense of duty to anyone.","TWN":"然而你沒有承擔他人責任的義務。"},"stage":{"bg":"MS_903","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하물며 유리한 전장을 구분하지 못하는 자는 범상하다고도 할 수 없지.","JPN":"ましてや戦場の勝ち負けを見分けられない者は平凡とも言えない。","ENG":"And someone who can't even recognize favorable ground isn't worthy of even being called ordinary.","TWN":"況且，一個分不清有利戰場的人，也無法獲得非凡的成就。"},"stage":{"bg":"MS_903","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"하! 망령 따위가 내게 궤변을 늘어놓는 거냐?","JPN":"は！　亡霊ごときが俺に詭弁を弄するか？","ENG":"Hah! A ghost dares lecture me with riddles?","TWN":"下！區區亡靈也敢對我胡言亂語？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"아니, 내가 할 말은 하나뿐이다.","JPN":"いや、私の言いたいことは一つだけだ。","ENG":"I only have one thing to say.","TWN":"不，我只有一句話要說。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"설령 네놈이 그분과 같은 <color=#ffd34c>운명</color>을 지녔다 한들…….","JPN":"たとえ貴様があの方のような<color=#ffd34c>運命</color>を持っているとしても……","ENG":"Even if you share the same <color=#ffd34c>fate</color> as he did...","TWN":"即便你擁有與那位相同的<color=#ffd34c>命運</color>……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"짊어진 자로서의 자각을 잃고 힘에 도취되는 순간, 결코 고귀한 존재가 될 수 없어.","JPN":"背負った者としての自覚を忘れ、力に溺れた瞬間、決して高貴な存在にはなれない。","ENG":"The moment you lose awareness of the burden you bear and get drunk on your own power, you'll never be noble.","TWN":"一旦失去作為承擔者的自覺，沉醉於力量之中，就絕不可能成為高貴的存在。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"지루한 입싸움은 끝내지.","JPN":"つまらない口喧嘩はここまでだ。","ENG":"Enough of this boring talk.","TWN":"無聊的口角該結束了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"마왕의 죽음에도 클리파의 잔재가 제 스스로 영향을 발휘한 이유는 알 수 없으나.","JPN":"魔王が死んだにも関わらずクリファの残滓が自ら影響力を発揮した理由はわからないが。","ENG":"I don't know why the remnants of Qlipha still stir despite the Demon Lord's death...","TWN":"雖然不知道即使在魔王死後，逆卡巴拉的殘餘為何仍能自行發揮影響。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"네놈이 할 수 있는 건 고작해야 시간을 버는 것이다.","JPN":"貴様にできることは、たかが時間稼ぎくらいだ。","ENG":"All you can do is stall for time.","TWN":"你能做的不過是拖延時間罷了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"한 가지 착각하고 있군, 네놈은.","JPN":"貴様は一つ勘違いをしている。","ENG":"You're mistaken about one thing.","TWN":"你有一個誤會。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지금의 내 존재를 규정하는 건, 마왕의 힘이 아니다.","JPN":"今の私の存在を規定しているのは、魔王の力ではない。","ENG":"My current existence isn't sustained by the Demon Lord's power.","TWN":"現在定義我存在的，不是魔王的力量。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"이 힘은… 설마?","JPN":"この力……まさか？","ENG":"This power... It can't be.","TWN":"這股力量是……難道？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"말했을 텐데. 유리한 전장을 구분하지 못하는 자는 범상하다고도 할 수 없다고.","JPN":"言ったはずだ。戦場の勝ち負けを見分けられない者は平凡とも言えないと。","ENG":"I told you. Someone who can't even recognize favorable ground isn't worthy of even being called ordinary.","TWN":"我已經說過了。分不清有利戰場的人，也無法獲得非凡的成就。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그 오만함은 언젠가 네 목숨을 조여오는 패착이 될 거다.","JPN":"その傲慢さはいつか貴様の首を絞めるだろう。","ENG":"That arrogance of yours will be your undoing.","TWN":"那份傲慢終將成為扼殺你生命的敗筆。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"흥. 목적을 달성했는데 굳이 번거로운 힘싸움을 할 필요야 없지.","JPN":"ふん。目的を達成したのにわざわざ面倒な戦いをする必要もない。","ENG":"Hmph. I've already achieved my goal. No need to waste effort fighting you now.","TWN":"哼。既然已經達到目的，就沒必要進行麻煩的爭鬥了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"CARANTISIR_ZODIAC_NULL_NULL","text":{"KOREA":"불필요한 싸움의 승리라도 원한다면 기꺼이 내어주마, 패배한 세계의 망령이여.","JPN":"不要な戦いの勝利を欲するなら、喜んで負けてやろう、敗北した世界の亡霊よ。","ENG":"But if you really want a hollow victory, I'll leave you that. Take it, ghost of a failed world.","TWN":"即使是不必要的戰鬥勝利，如果你想要，我也願意給予你，失敗世界的亡靈啊。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"사라졌다…?","JPN":"消えた……？","ENG":"He vanished...?","TWN":"消失了…？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};